# OEIS sequence: A396340

from math import isqrt
from sympy import prime
def is_fibonacci(n):
    def is_sq(x):
        s = isqrt(x)
        return s*s == x
    return is_sq(5*n*n + 4) or is_sq(5*n*n - 4)
def sequence(n_terms):
    results = []
    for i in range(2, n_terms + 1):
        gap = prime(i) - prime(i-1)
        if is_fibonacci(gap):
            results.append(prime(i))
    return results
print(sequence(150))

